const r=$input.first().json;
const results=r.results||[];
const now=Date.now();
const RUN_STUCK=2*3600*1000;
const WAIT_STUCK=24*3600*1000;
const running=[],waiting=[];
for(const p of results){
  const pr=p.properties||{};
  const status=pr['ai狀態']?.status?.name||'';
  const mode=pr['ai模式']?.select?.name||'';
  if(!mode)continue;
  const edited=new Date(p.last_edited_time).getTime();
  const name=(pr['明細名稱']?.title||[]).map(t=>t.plain_text).join('')||'(未命名)';
  const id=p.id.replace(/-/g,'');
  if(status==='執行中'&&now-edited>RUN_STUCK){
    running.push({name,mode,id,h:((now-edited)/3600000).toFixed(1)});
  }else if(status==='待執行'&&now-edited>WAIT_STUCK){
    waiting.push({name,mode,id,h:((now-edited)/3600000).toFixed(1)});
  }
}
const nowTW=new Date().toLocaleString('zh-TW',{timeZone:'Asia/Taipei'});
let msg='💓 嗨嗨總管心跳 '+nowTW+'\n細部流程棒次共 '+results.length+' 筆。';
if(!running.length&&!waiting.length){
  msg+='\n無卡關、無久候，一切正常。';
}else{
  if(running.length){msg+='\n\n⚠️ 卡關（執行中久未動 >2hr）'+running.length+' 個：\n'+running.slice(0,15).map(s=>'• '+s.name+'（'+s.mode+'）卡 '+s.h+' 小時  db06='+s.id).join('\n');}
  if(waiting.length){msg+='\n\n⏳ 久候放行（待執行 >24hr）'+waiting.length+' 個：\n'+waiting.slice(0,15).map(s=>'• '+s.name+'（'+s.mode+'）等 '+s.h+' 小時  db06='+s.id).join('\n');}
}
return [{json:{msg,running:running.length,waiting:waiting.length,total:results.length}}];
